diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..d2b0cec1f518 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3065,6 +3065,7 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3251,6 +3252,86 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
         if (auto *V = foldAndOrOfICmps(ICmp0, ICmp1, SI, IsAnd,
                                        /* IsLogical */ true))
           return replaceInstUsesWith(SI, V);
+
+    // select (icmp1 && A), icmp2, false -> select A, (icmp1 && icmp2), false
+    // if icmp1 && icmp2 can be folded into a single icmp
+    if (IsAnd && match(CondVal, m_LogicalAnd(m_Value(A), m_Value(B))) &&
+        CondVal->hasOneUse()) {
+      ICmpInst *ICmp1 = nullptr;
+      Value *OtherCond = nullptr;
+      if (auto *IC = dyn_cast<ICmpInst>(A)) {
+        ICmp1 = IC;
+        OtherCond = B;
+      } else if (auto *IC = dyn_cast<ICmpInst>(B)) {
+        ICmp1 = IC;
+        OtherCond = A;
+      }
+
+      if (ICmp1 && isa<ICmpInst>(Op1))
+        if (Value *V = foldAndOrOfICmps(ICmp1, cast<ICmpInst>(Op1), SI,
+                                        /*IsAnd=*/true, /*IsLogical=*/true))
+          return SelectInst::Create(OtherCond, V, Zero);
+    }
+
+    // select icmp1, (icmp2 && A), false -> select A, (icmp1 && icmp2), false
+    // if icmp1 && icmp2 can be folded into a single icmp
+    if (IsAnd && match(Op1, m_LogicalAnd(m_Value(A), m_Value(B))) &&
+        Op1->hasOneUse()) {
+      ICmpInst *ICmp2 = nullptr;
+      Value *OtherCond = nullptr;
+      if (auto *IC = dyn_cast<ICmpInst>(A)) {
+        ICmp2 = IC;
+        OtherCond = B;
+      } else if (auto *IC = dyn_cast<ICmpInst>(B)) {
+        ICmp2 = IC;
+        OtherCond = A;
+      }
+
+      if (ICmp2 && isa<ICmpInst>(CondVal))
+        if (Value *V = foldAndOrOfICmps(cast<ICmpInst>(CondVal), ICmp2, SI,
+                                        /*IsAnd=*/true, /*IsLogical=*/true))
+          return SelectInst::Create(OtherCond, V, Zero);
+    }
+
+    // select (icmp1 || A), true, icmp2 -> select A, true, (icmp1 || icmp2)
+    // if icmp1 || icmp2 can be folded into a single icmp
+    if (!IsAnd && match(CondVal, m_LogicalOr(m_Value(A), m_Value(B))) &&
+        CondVal->hasOneUse()) {
+      ICmpInst *ICmp1 = nullptr;
+      Value *OtherCond = nullptr;
+      if (auto *IC = dyn_cast<ICmpInst>(A)) {
+        ICmp1 = IC;
+        OtherCond = B;
+      } else if (auto *IC = dyn_cast<ICmpInst>(B)) {
+        ICmp1 = IC;
+        OtherCond = A;
+      }
+
+      if (ICmp1 && isa<ICmpInst>(Op1))
+        if (Value *V = foldAndOrOfICmps(ICmp1, cast<ICmpInst>(Op1), SI,
+                                        /*IsAnd=*/false, /*IsLogical=*/true))
+          return SelectInst::Create(OtherCond, One, V);
+    }
+
+    // select icmp1, true, (icmp2 || A) -> select A, true, (icmp1 || icmp2)
+    // if icmp1 || icmp2 can be folded into a single icmp
+    if (!IsAnd && match(Op1, m_LogicalOr(m_Value(A), m_Value(B))) &&
+        Op1->hasOneUse()) {
+      ICmpInst *ICmp2 = nullptr;
+      Value *OtherCond = nullptr;
+      if (auto *IC = dyn_cast<ICmpInst>(A)) {
+        ICmp2 = IC;
+        OtherCond = B;
+      } else if (auto *IC = dyn_cast<ICmpInst>(B)) {
+        ICmp2 = IC;
+        OtherCond = A;
+      }
+
+      if (ICmp2 && isa<ICmpInst>(CondVal))
+        if (Value *V = foldAndOrOfICmps(cast<ICmpInst>(CondVal), ICmp2, SI,
+                                        /*IsAnd=*/false, /*IsLogical=*/true))
+          return SelectInst::Create(OtherCond, One, V);
+    }
   }

   // select (a || b), c, false -> select a, c, false
@@ -3323,6 +3404,7 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   return nullptr;
 }

+
 // Return true if we can safely remove the select instruction for std::bit_ceil
 // pattern.
 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,

